 1→/**
 2→ * Agent 類型
 3→ */
 4→export type AgentType = 'codex' | 'claude' | 'gemini';
 5→
 6→/**
 7→ * CLI 選項
 8→ */
 9→export interface CliOptions {
10→  agentType: AgentType;
11→  raw: boolean;
12→  project?: string;
13→  follow: boolean;
14→  verbose: boolean;
15→  /** Suppress non-error output messages */
16→  quiet: boolean;
17→  /** File polling interval in milliseconds (default: 500) */
18→  sleepInterval: number;
19→  /** Number of initial lines to show per file (default: all) */
20→  lines?: number;
21→  /** Claude/Codex: tail subagent log (true = latest, string = specific ID) */
22→  subagent?: string | true;
23→  /** Claude/Codex: interactive mode for switching between main session and subagents (Codex: Phase 3) */
24→  interactive: boolean;
25→  /** Claude/Codex: include subagent content in output (non-interactive mode) */
26→  withSubagents: boolean;
27→  /** Auto-switch to latest main session in project */
28→  autoSwitch: boolean;
29→  /** Claude/Codex: auto-open tmux pane for each new subagent (Codex: Phase 2) */
30→  pane: boolean;
31→  /** Optional session ID to load (partial match supported) */
32→  sessionId?: string;
33→}
34→
35→/**
36→ * Parser 設定選項
37→ */
38→export interface ParserOptions {
39→  verbose: boolean;
40→}
41→
42→/**
43→ * Session 檔案資訊
44→ */
45→export interface SessionFile {
46→  path: string;
47→  mtime: Date;
48→  agentType: AgentType;
49→  /** Claude Code custom session title (from /rename command) */
50→  customTitle?: string;
