53→/**
54→ * 專案資訊（用於 auto-switch）
55→ */
56→export interface ProjectInfo {
57→  /** 專案目錄路徑（用於 session 搜尋範圍） */
58→  projectDir: string;
59→  /** 顯示名稱（用於日誌輸出） */
60→  displayName?: string;
61→}
62→
63→/**
64→ * Claude Session 查找結果（支援 subagent 關聯）
65→ * 當指定 subagent ID 時，會同時返回主 session 和 subagent
66→ */
67→export interface ClaudeSessionResult {
