72→/**
73→ * JSONL 解析結果
74→ */
75→export interface ParsedLine {
76→  type: string;
77→  timestamp: string;
78→  raw: unknown;
79→  formatted: string;
80→  /** Tool 名稱（僅 function_call 類型使用，用於顏色判斷） */
81→  toolName?: string;
82→  /** 來源標籤（多檔案監控時用於區分來源，如 "[MAIN]" 或 "[a0627b6]"） */
83→  sourceLabel?: string;
84→  /** 是否為 Task (or Agent) tool_use（用於早期 Subagent 偵測） */
85→  isTaskToolUse?: boolean;
86→  /** Task (or Agent) tool_use 的 description 欄位（用於 pane 命名） */
87→  taskDescription?: string;
88→  /** Whether this is a custom-title event (Claude only) */
