 32→/**
 33→ * Tool 類別（用於顏色區分）
 34→ */
 35→export type ToolCategory =
 36→  | 'shell'
 37→  | 'file'
 38→  | 'search'
 39→  | 'web'
 40→  | 'task'
 41→  | 'other';
 42→
 43→/**
 44→ * 根據 tool 名稱取得類別
 45→ */
 46→export function getToolCategory(toolName: string): ToolCategory {
 47→  switch (toolName.toLowerCase()) {
 48→    case 'bash':
 49→    case 'shell':
 50→    case 'shell_command':
 51→    case 'run_shell_command':
 52→      return 'shell';
 53→    case 'read':
 54→    case 'edit':
 55→    case 'write':
 56→    case 'read_file':
 57→    case 'edit_file':
 58→    case 'write_file':
 59→      return 'file';
 60→    case 'grep':
 61→    case 'glob':
 62→      return 'search';
 63→    case 'webfetch':
 64→    case 'websearch':
 65→      return 'web';
 66→    case 'task':
 67→    case 'agent':
 68→      return 'task';
 69→    default:
 70→      return 'other';
 71→  }
 72→}
