 74→/**
 75→ * 格式化 tool_use，顯示關鍵參數摘要
 76→ */
 77→export function formatToolUse(
 78→  name: string,
 79→  input?: Record<string, unknown>,
 80→  options: FormatToolOptions = {}
 81→): string {
 82→  const { verbose = false } = options;
 83→
 84→  if (!input) return `[TOOL: ${name}]`;
 85→
 86→  switch (name) {
 87→    case 'Task':
 88→    case 'Agent': {
 89→      const prompt = input.prompt as string | undefined;
 90→      if (prompt) {
 91→        const summary = truncate(prompt, {
 92→          verbose,
 93→          headLength: 50,
 94→          tailLength: 50,
 95→        });
 96→        return `[TOOL: ${name}] ${summary}`;
 97→      }
 98→      return `[TOOL: ${name}]`;
 99→    }
100→
101→    case 'Grep': {
102→      const pattern = input.pattern as string | undefined;
103→      const path = input.path as string | undefined;
104→      const pathStr = path ? ` in ${path}` : '';
105→      return `[TOOL: Grep] "${pattern || ''}"${pathStr}`;
106→    }
107→
108→    case 'Bash': {
109→      const command = input.command as string | undefined;
110→      if (command) {
111→        const summary = truncate(command, {
112→          verbose,
113→          headLength: 80,
114→          tailLength: 40,
115→        });
116→        return `$ ${summary}`;
117→      }
118→      return `$ (empty)`;
119→    }
120→
121→    case 'Read': {
122→      const filePath = input.file_path as string | undefined;
123→      return `[TOOL: Read] ${filePath || ''}`;
124→    }
125→
126→    case 'Edit': {
127→      const filePath = input.file_path as string | undefined;
128→      return `[TOOL: Edit] ${filePath || ''}`;
129→    }
130→
131→    case 'Write': {
132→      const filePath = input.file_path as string | undefined;
133→      return `[TOOL: Write] ${filePath || ''}`;
134→    }
135→
136→    case 'Glob': {
137→      const pattern = input.pattern as string | undefined;
138→      const path = input.path as string | undefined;
139→      const pathStr = path ? ` in ${path}` : '';
140→      return `[TOOL: Glob] "${pattern || ''}"${pathStr}`;
141→    }
142→
143→    case 'LSP': {
144→      const operation = input.operation as string | undefined;
145→      const filePath = input.filePath as string | undefined;
146→      return `[TOOL: LSP] ${operation || ''} ${filePath || ''}`;
147→    }
148→
149→    case 'WebFetch': {
150→      const url = input.url as string | undefined;
151→      return `[TOOL: WebFetch] ${url || ''}`;
152→    }
153→
154→    case 'WebSearch': {
155→      const query = input.query as string | undefined;
156→      return `[TOOL: WebSearch] "${query || ''}"`;
157→    }
158→
159→    case 'TodoWrite':
160→    case 'TaskCreate':
161→    case 'TaskUpdate':
162→    case 'TaskList':
163→    case 'TaskGet': {
164→      return `[TOOL: ${name}]`;
165→    }
166→
167→    // Codex 工具
168→    case 'shell':
169→    case 'shell_command': {
170→      const command = input.command as string | string[] | undefined;
171→      // Codex shell command 格式: ['/bin/zsh', '-lc', 'actual command'] 或直接字串
172→      const cmdStr = Array.isArray(command)
173→        ? command.slice(2).join(' ')
174→        : command || '';
175→      if (cmdStr) {
176→        const summary = truncate(cmdStr, {
177→          verbose,
178→          headLength: 80,
179→          tailLength: 40,
180→        });
181→        return `$ ${summary}`;
182→      }
183→      return `[TOOL: shell]`;
184→    }
185→
186→    // Gemini 工具（snake_case 命名）
187→    case 'run_shell_command': {
188→      // Gemini shell command - 參數可能是 command 或其他欄位
189→      const command = (input.command ||
190→        input.cmd ||
191→        Object.values(input).find(
192→          (v) => typeof v === 'string' && v.length > 0
193→        )) as string | undefined;
194→      if (command) {
195→        const summary = truncate(command, {
196→          verbose,
197→          headLength: 80,
198→          tailLength: 40,
199→        });
200→        return `$ ${summary}`;
201→      }
202→      return `$ (empty)`;
203→    }
204→
205→    case 'read_file': {
206→      const filePath = input.file_path as string | undefined;
207→      return `[TOOL: read_file] ${filePath || ''}`;
208→    }
209→
210→    case 'edit_file': {
211→      const filePath = input.file_path as string | undefined;
212→      return `[TOOL: edit_file] ${filePath || ''}`;
213→    }
214→
215→    case 'write_file': {
216→      const filePath = input.file_path as string | undefined;
217→      return `[TOOL: write_file] ${filePath || ''}`;
218→    }
219→
220→    default: {
221→      // 其他 tool 顯示第一個有意義的參數
222→      const firstValue = Object.values(input).find(
223→        (v) => typeof v === 'string' && v.length > 0
224→      ) as string | undefined;
225→      if (firstValue) {
226→        const summary = truncate(firstValue, {
227→          verbose,
228→          headLength: 40,
229→          tailLength: 20,
230→        });
231→        return `[TOOL: ${name}] ${summary}`;
232→      }
233→      return `[TOOL: ${name}]`;
234→    }
235→  }
236→}
