 81→async function main(): Promise<void> {
 82→  const options = parseArgs(process.argv);
 83→
 84→  // 選擇 Agent
 85→  const agent: Agent =
 86→    options.agentType === 'codex'
 87→      ? new CodexAgent({ verbose: options.verbose })
 88→      : options.agentType === 'gemini'
 89→        ? new GeminiAgent({ verbose: options.verbose })
 90→        : new ClaudeAgent({ verbose: options.verbose });
 91→
 92→  // 選擇 Formatter
 93→  const formatter: Formatter = options.raw
 94→    ? new RawFormatter()
 95→    : new PrettyFormatter();
 96→
 97→  // 找到目標 session 檔案
 98→  let sessionFile: SessionFile | null = null;
 99→  let subagentFile: SessionFile | null = null; // Claude subagent 關聯
100→
101→  // 判斷搜尋模式
102→  if (options.sessionId) {
103→    // 使用 sessionId 搜尋特定 session
104→    log(
105→      options.quiet,
106→      chalk.gray(
107→        `Searching for ${options.agentType} session "${options.sessionId}"...`
108→      )
109→    );
110→
111→    const finder = agent.finder;
112→    if (!finder.findBySessionId) {
113→      console.error(
114→        chalk.red(
115→          `Session ID lookup not supported for ${options.agentType} agent`
116→        )
117→      );
118→      process.exit(1);
119→    }
120→
121→    const result = await finder.findBySessionId(options.sessionId, {
122→      project: options.project,
123→    });
124→
125→    if (!result) {
126→      const projectInfo = options.project
127→        ? ` in project "${options.project}"`
128→        : '';
129→      console.error(
130→        chalk.red(
131→          `No session found matching "${options.sessionId}"${projectInfo}`
132→        )
133→      );
134→      process.exit(1);
135→    }
136→
137→    // 判斷是否為 ClaudeSessionResult（有 main 和 subagent）
138→    if ('main' in result && 'subagent' in result) {
139→      const claudeResult = result as ClaudeSessionResult;
140→      sessionFile = claudeResult.main;
141→      subagentFile = claudeResult.subagent || null;
142→      log(
143→        options.quiet,
144→        chalk.green(`Found main session: ${sessionFile.path}`)
145→      );
146→      if (subagentFile) {
147→        log(options.quiet, chalk.green(`Found subagent: ${subagentFile.path}`));
148→      }
149→    } else {
150→      sessionFile = result as SessionFile;
151→      log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
152→    }
153→    logSessionMeta(sessionFile, options.quiet);
154→  } else if (
155→    (options.agentType === 'claude' || options.agentType === 'codex') &&
156→    options.subagent !== undefined
157→  ) {
158→    // Claude/Codex subagent 模式（使用 --subagent 選項）
159→    log(
160→      options.quiet,
161→      chalk.gray(`Searching for latest ${options.agentType} subagent...`)
162→    );
163→
164→    const finder = agent.finder;
165→    if (finder.findSubagent) {
166→      const subagentId =
167→        typeof options.subagent === 'string' ? options.subagent : undefined;
168→
169→      sessionFile = await finder.findSubagent({
170→        project: options.project,
171→        subagentId,
172→      });
173→
174→      if (!sessionFile) {
175→        const idInfo = subagentId ? ` (id: ${subagentId})` : '';
176→        const projectInfo = options.project
177→          ? ` in project "${options.project}"`
178→          : '';
179→        console.error(
180→          chalk.red(`No subagent file found${idInfo}${projectInfo}`)
181→        );
182→        process.exit(1);
183→      }
184→    }
185→    log(options.quiet, chalk.green(`Found: ${sessionFile?.path}`));
186→    log(
187→      options.quiet,
188→      chalk.gray(`Modified: ${sessionFile?.mtime.toLocaleString()}`)
189→    );
190→  } else {
191→    // 預設模式：找最新的 session
192→    log(
193→      options.quiet,
194→      chalk.gray(`Searching for latest ${options.agentType} session...`)
195→    );
196→
197→    sessionFile = await agent.finder.findLatest({
198→      project: options.project,
199→    });
200→

200→
201→    if (!sessionFile) {
202→      console.error(
203→        chalk.red(
204→          `No session file found for ${options.agentType}${options.project ? ` (project: ${options.project})` : ''}`
205→        )
206→      );
207→      process.exit(1);
208→    }
209→
210→    log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
211→    logSessionMeta(sessionFile, options.quiet);
212→  }
213→
214→  if (!sessionFile) {
215→    console.error(chalk.red('No session file found'));
216→    process.exit(1);
217→  }
218→
219→  // 監控模式判斷：
220→  // 1. Claude 主 session 模式 → Claude 多檔案監控
221→  // 2. Codex 主 session + withSubagents/pane → Codex 多檔案監控
222→  // 3. --subagent 選項 → 單檔案監控（Claude/Codex）
223→  // 4. 其他 agent → 單檔案監控
224→  if (options.agentType === 'claude' && options.subagent === undefined) {
225→    if (options.interactive) {
226→      // Interactive 模式：使用 SessionManager 管理輸出切換
227→      await startClaudeInteractiveWatch(
228→        sessionFile,
229→        formatter,
230→        options,
231→        subagentFile
232→      );
233→    } else {
234→      // 普通模式：所有來源輸出到 console
235→      await startClaudeMultiWatch(
236→        sessionFile,
237→        formatter,
238→        options,
239→        subagentFile
240→      );
241→    }
242→  } else if (options.agentType === 'codex' && options.interactive) {
243→    // Codex 互動模式（Phase 3）
244→    await startCodexInteractiveWatch(sessionFile, formatter, options);
245→  } else if (
246→    options.agentType === 'codex' &&
247→    options.subagent === undefined &&
248→    (options.withSubagents || options.pane)
249→  ) {
250→    // Codex 多檔案監控（主 session + subagents）
251→    await startCodexMultiWatch(sessionFile, formatter, options);
252→  } else {
253→    // 其他 agent 或 Claude/Codex subagent 模式：單檔案監控
254→    await startSingleWatch(agent, sessionFile, formatter, options);
255→  }
256→}
