258→/**
259→ * Claude 多檔案監控（主 session + subagents）
260→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
261→ */
262→async function startClaudeMultiWatch(
263→  sessionFile: SessionFile,
264→  formatter: Formatter,
265→  options: CliOptions,
266→  initialSubagent: SessionFile | null = null
267→): Promise<void> {
268→  const projectDir = dirname(sessionFile.path);
269→  let subagentsDir = getSubagentsDir(sessionFile.path);
270→
271→  // 建立監控檔案列表（主 session）
272→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
273→
274→  // 只有在 withSubagents 為 true 時才掃描 subagent
275→  const existingAgentIds = new Set<string>();
276→  if (options.withSubagents) {
277→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
278→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
279→    for (const id of dirAgentIds) {
280→      existingAgentIds.add(id);
281→    }
282→
283→    // 如果有從 sessionId 指定的 subagent，確保它被加入
284→    if (initialSubagent) {
285→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
286→        /^agent-/,
287→        ''
288→      );
289→      existingAgentIds.add(initialAgentId);
290→    }
291→
292→    const existingSubagentFiles = await buildSubagentFiles(
293→      subagentsDir,
294→      existingAgentIds
295→    );
296→    for (const { agentId, path } of existingSubagentFiles) {
297→      files.push({ path, label: makeAgentLabel(agentId) });
298→    }
299→
300→    if (existingAgentIds.size > 0) {
301→      log(
302→        options.quiet,
303→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
304→      );
305→    }
306→  }
307→  log(options.quiet, chalk.gray('---'));
308→
309→  // 為每個來源建立獨立的 parser
310→  let parsers = new Map<string, LineParser>();
311→  for (const file of files) {
312→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
313→    parsers.set(file.label, parserAgent.parser);
314→  }
315→
316→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
317→  if (!options.follow && options.withSubagents && files.length > 1) {
318→    await outputTimeSorted(files, parsers, formatter, options);
319→    process.exit(0);
320→  }
321→
322→  let multiWatcher = new MultiFileWatcher();
323→
324→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
325→  let paneManager: PaneManager | null = null;
326→  if (options.pane) {
327→    const controller = createTerminalController();
328→    if (controller.isAvailable()) {
329→      paneManager = new PaneManager(
330→        controller,
331→        (agentId, _subagentPath) => {
332→          // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
333→          // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
334→          const runtime = `"${process.argv[0]}"`;
335→          const script = `"${process.argv[1]}"`;
336→          return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
337→        },
338→        (msg) => log(options.quiet, chalk.gray(msg))
339→      );
340→    } else {
341→      log(
342→        options.quiet,
343→        chalk.yellow('Warning: tmux not detected, --pane disabled')
344→      );
345→    }
346→  }
347→
348→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
349→  const pm = paneManager; // 閉包捕獲，不受外部重賦值影響
350→  const openPaneForSubagent = pm
351→    ? (agentId: string, subagentPath: string, description?: string) => {
352→        pm.openPane(agentId, subagentPath, description).catch((err) => {
353→          log(
354→            options.quiet,
355→            chalk.yellow(`[pane] Failed to open pane: ${err}`)
356→          );
357→        });
358→      }
359→    : undefined;
360→
361→  const onSubagentDone = pm
362→    ? (agentId: string) => {
363→        const subagentPath = buildSubagentPath(subagentsDir, agentId);
364→
365→        // 先讀取並輸出最後的 assistant 訊息，再關閉 pane
366→        (async () => {
367→          try {
368→            const parts = await readLastAssistantMessage(
369→              subagentPath,
370→              options.verbose
371→            );
372→            const label = makeAgentLabel(agentId);
373→            for (const part of parts) {
374→              part.sourceLabel = label;
375→              console.log(formatter.format(part));
376→            }
377→          } catch {
378→            // 讀取失敗不影響 pane 關閉
379→          } finally {
380→            await pm.closePaneByAgentId(agentId);
381→          }
382→        })().catch(() => {});
383→      }
384→    : undefined;
385→
386→  const hasPaneCallback = pm
387→    ? (agentId: string) => pm.hasPaneForAgent(agentId)
388→    : undefined;
389→
390→  // pane 模式下，進入時既有 subagent 加入 suppress set，避免歷史內容污染 main pane
391→  const suppressedForPane = pm ? new Set(existingAgentIds) : new Set<string>();
392→
393→  const shouldOutput = pm
394→    ? (label: string) => {
395→        if (label === MAIN_LABEL) return true;
396→        const agentId = extractAgentIdFromLabel(label);
397→        if (suppressedForPane.has(agentId)) return false;
398→        return !pm.hasPaneForAgent(agentId);
399→      }

400→    : undefined;
401→
402→  // 建立 SubagentDetector（整合 early detection 和 fallback detection）
403→  let detector = new SubagentDetector(existingAgentIds, {
404→    subagentsDir,
405→    output: new ConsoleOutputHandler(),
406→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
407→    session: new NoOpSessionHandler(),
408→    enabled: options.follow && options.withSubagents,
409→    onNewSubagent: openPaneForSubagent,
410→    onSubagentEnter: openPaneForSubagent,
411→    onSubagentDone,
412→    hasPane: hasPaneCallback,
413→  });
414→  detector.startDirectoryWatch();
415→
416→  // ========== Non-Interactive Super-Follow ==========
417→  let currentSessionPath = sessionFile.path;
418→
419→  const switchToSession = async (
420→    nextSessionFile: SessionFile
421→  ): Promise<void> => {
422→    // 停止現有監控
423→    detector?.stop();
424→    multiWatcher.stop();
425→
426→    // 更新當前 session 路徑
427→    currentSessionPath = nextSessionFile.path;
428→
429→    // 重新初始化監控
430→    const newSessionId = basename(nextSessionFile.path, '.jsonl');
431→    const newSubagentsDir = getSubagentsDir(nextSessionFile.path);
432→
433→    const newFiles: WatchedFile[] = [
434→      { path: nextSessionFile.path, label: MAIN_LABEL },
435→    ];
436→    const newExistingAgentIds = new Set<string>();
437→
438→    // 掃描現有的 subagents
439→    if (options.withSubagents) {
440→      const dirAgentIds = await scanForNewSubagents(newSubagentsDir, new Set());
441→      for (const id of dirAgentIds) {
442→        newExistingAgentIds.add(id);
443→      }
444→
445→      const existingSubagentFiles = await buildSubagentFiles(
446→        newSubagentsDir,
447→        newExistingAgentIds
448→      );
449→      for (const { agentId, path } of existingSubagentFiles) {
450→        newFiles.push({ path, label: makeAgentLabel(agentId) });
451→      }
452→
453→      if (newExistingAgentIds.size > 0) {
454→        log(
455→          options.quiet,
456→          chalk.gray(`Found ${newExistingAgentIds.size} subagent(s)`)
457→        );
458→      }
459→    }
460→
461→    // 更新 suppress set：清空後填入新 session 的既有 subagent
462→    if (pm) {
463→      suppressedForPane.clear();
464→      for (const agentId of newExistingAgentIds) suppressedForPane.add(agentId);
465→    }
466→
467→    // 輸出切換訊息
468→    const switchTitle = await readCustomTitle(nextSessionFile.path);
469→    const switchTitleSuffix = switchTitle ? ` "${switchTitle}"` : '';
470→    log(
471→      options.quiet,
472→      chalk.gray(
473→        `--- Switched to session ${newSessionId}${switchTitleSuffix} ---`
474→      )
475→    );
476→    log(options.quiet, chalk.gray('---'));
477→
478→    // 重新建立 parsers
479→    const newParsers = new Map<string, LineParser>();
480→    for (const file of newFiles) {
481→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
482→      newParsers.set(file.label, parserAgent.parser);
483→    }
484→    parsers = newParsers;
485→
486→    // 重新建立 multiWatcher（先建立，但還不啟動）
487→    const newMultiWatcher = new MultiFileWatcher();
488→
489→    // 重新建立 detector（捕獲新的 multiWatcher，沿用 pane 回呼）
490→    const newDetector = new SubagentDetector(newExistingAgentIds, {
491→      subagentsDir: newSubagentsDir,
492→      output: new ConsoleOutputHandler(),
493→      watcher: { addFile: (f) => newMultiWatcher.addFile(f) },
494→      session: new NoOpSessionHandler(),
495→      enabled: options.follow && options.withSubagents,
496→      onNewSubagent: openPaneForSubagent,
497→      onSubagentEnter: openPaneForSubagent,
498→      onSubagentDone,
499→      hasPane: hasPaneCallback,
500→    });
501→    newDetector.startDirectoryWatch();
502→
503→    // 更新外層變數
504→    subagentsDir = newSubagentsDir;
505→    multiWatcher = newMultiWatcher;
506→    detector = newDetector;
507→
508→    // 重新啟動監控
509→    await multiWatcher.start(newFiles, {
510→      follow: options.follow,
511→      pollInterval: options.sleepInterval,
512→      initialLines: options.lines,
513→      onLine: createOnLineHandler({
514→        parsers,
515→        formatter,
516→        detector,
517→        onOutput: (formatted) => console.log(formatted),
518→        verbose: options.verbose,
519→        shouldOutput,
520→      }),
521→      onError: (error) => {
522→        console.error(chalk.red(`Error: ${error.message}`));
523→      },
524→    });
525→  };
526→
527→  const superFollow = createSuperFollowController({
528→    projectDir,
529→    getCurrentPath: () => currentSessionPath,
530→    onSwitch: switchToSession,
531→    autoSwitch: options.autoSwitch,
532→    findLatestInProject: findLatestMainSessionInProject,
533→  });
534→
535→  // 處理中斷信號
536→  process.on('SIGINT', () => {
537→    superFollow.stop();
538→    console.log(chalk.gray('\nStopping...'));
539→    detector?.stop();
540→    multiWatcher.stop();
541→    // best-effort 清理所有 pane（async 但不等待，因為即將 exit）
542→    paneManager?.closeAll();
543→    process.exit(0);
544→  });
545→
546→  await multiWatcher.start(files, {
547→    follow: options.follow,
548→    pollInterval: options.sleepInterval,
549→    initialLines: options.lines,
550→    onLine: createOnLineHandler({
551→      parsers,
552→      formatter,
553→      detector,
554→      onOutput: (formatted) => console.log(formatted),
555→      verbose: options.verbose,
556→      shouldOutput,
557→    }),
558→    onError: (error) => {
559→      console.error(chalk.red(`Error: ${error.message}`));
560→    },
561→  });
562→
563→  // 如果不是 follow 模式，結束程式
564→  if (!options.follow) {
565→    process.exit(0);
566→  }
567→
568→  // 啟動 super-follow
569→  superFollow.start();
570→
571→  // 保持程式運行
572→  log(options.quiet, chalk.gray('Watching for changes... (Ctrl+C to stop)'));
573→}
