591→  for (const file of files) {
592→    const parser = parsers.get(file.label);
593→    if (!parser) continue;
594→
595→    // 讀取檔案內容
596→    const bunFile = Bun.file(file.path);
597→    if (!(await bunFile.exists())) continue;
598→
599→    const content = await bunFile.text();

  1→import { stat } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ClaudeSessionResult,
  8→  ParsedLine,
  9→  ParserOptions,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import {
 13→  contentToString,
