 17→import { formatToolUse, isSubagentTool } from '../../utils/format-tool.ts';
 18→import { readCustomTitle } from '../../claude/custom-title.ts';
 19→
 20→/** JSONL event type for Claude /rename command */
 21→const CUSTOM_TITLE_TYPE = 'custom-title';
 22→
 23→/**
 24→ * Claude Code Session Finder
 25→ * 目錄結構: ~/.claude/projects/{encoded-path}/{UUID}.jsonl
 26→ */
 27→class ClaudeSessionFinder implements SessionFinder {
 28→  private baseDir: string;
 29→
 30→  constructor() {
 31→    this.baseDir = join(homedir(), '.claude', 'projects');
 32→  }
 33→
 34→  getBaseDir(): string {
 35→    return this.baseDir;
 36→  }
 37→
 38→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 39→    const glob = new Glob('**/*.jsonl');
 40→    const files: { path: string; mtime: Date }[] = [];
 41→
 42→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 43→      const filename = file.split('/').pop() || '';
 44→
 45→      // 排除 agent-* 開頭的檔案
 46→      if (filename.startsWith('agent-')) continue;
 47→
 48→      // 只匹配 UUID 格式的檔案名
 49→      const uuidPattern =
 50→        /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
 51→      if (!uuidPattern.test(filename)) continue;
 52→
 53→      // 如果有 project filter，做模糊比對
 54→      if (options.project) {
 55→        const pattern = options.project.toLowerCase();
 56→        // 對路徑做模糊比對（包含專案目錄名稱）
 57→        if (!file.toLowerCase().includes(pattern)) continue;
 58→      }
 59→
 60→      try {
 61→        const stats = await stat(file);
 62→        files.push({ path: file, mtime: stats.mtime });
 63→      } catch {
 64→        // 忽略無法讀取的檔案
 65→      }
 66→    }
 67→
 68→    if (files.length === 0) return null;
 69→
 70→    // 按修改時間排序，取最新的
 71→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 72→
 73→    const latest = files[0];
 74→    if (!latest) return null;
 75→
 76→    const customTitle = await readCustomTitle(latest.path);
 77→    return {
 78→      path: latest.path,
 79→      mtime: latest.mtime,
 80→      agentType: 'claude',
 81→      ...(customTitle ? { customTitle } : {}),
 82→    };
 83→  }
 84→
 85→  /**
 86→   * 找到 subagent 檔案
 87→   * 新結構: {sessionId}/subagents/agent-{7位hex}.jsonl
 88→   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
 89→   */
 90→  async findSubagent(options: {
 91→    project?: string;
 92→    subagentId?: string;
 93→  }): Promise<SessionFile | null> {
 94→    const { project, subagentId } = options;
 95→
 96→    // 決定 glob pattern（新結構：{UUID}/subagents/ 目錄下）
 97→    const pattern = subagentId
 98→      ? `**/*/subagents/agent-${subagentId}.jsonl`
 99→      : '**/*/subagents/agent-*.jsonl';
100→
101→    const glob = new Glob(pattern);
102→    const files: { path: string; mtime: Date }[] = [];
103→
104→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
105→      const filename = file.split('/').pop() || '';
106→
107→      // 驗證 subagent 檔名格式: agent-{7~40位十六進制}.jsonl
108→      const subagentPattern = /^agent-[0-9a-f]{7,40}\.jsonl$/i;
109→      if (!subagentPattern.test(filename)) continue;
110→
111→      // project filter
112→      if (project && !file.toLowerCase().includes(project.toLowerCase())) {
113→        continue;
114→      }
115→
116→      try {
117→        const stats = await stat(file);
118→        files.push({ path: file, mtime: stats.mtime });
119→      } catch {
120→        // 忽略無法讀取的檔案
121→      }
122→    }
123→
124→    if (files.length === 0) return null;
125→
126→    // 按修改時間排序，取最新的
127→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
128→    const latest = files[0];
129→    if (!latest) return null;
130→
131→    return {
132→      path: latest.path,
133→      mtime: latest.mtime,
134→      agentType: 'claude',
135→    };
136→  }
137→
138→  /**
139→   * 依 session ID 查找 session 檔案
140→   * 支援主 session（UUID）和 subagent（7位hex）
141→   * 當指定 subagent ID 時，會同時返回主 session 和 subagent
142→   */
143→  async findBySessionId(
144→    sessionId: string,
145→    options: { project?: string }
146→  ): Promise<SessionFile | ClaudeSessionResult | null> {
147→    const idType = this.detectIdType(sessionId);
148→
149→    // 如果是主 session UUID 或未知類型，先嘗試找主 session
150→    if (idType === 'main' || idType === 'unknown') {
151→      const mainResult = await this.findMainBySessionId(sessionId, options);
152→      if (mainResult) return mainResult;
153→    }
154→
155→    // 如果是 subagent ID 或未知類型（且主 session 沒找到），嘗試找 subagent
156→    if (idType === 'subagent' || idType === 'unknown') {
157→      const subagentResult = await this.findSubagentBySessionId(
158→        sessionId,
159→        options
160→      );
161→      if (subagentResult) {
162→        // 反推主 session
163→        const mainPath = this.getMainSessionFromSubagent(subagentResult.path);
164→        if (mainPath) {
165→          try {
166→            const [mainStats, mainTitle] = await Promise.all([
167→              stat(mainPath),
168→              readCustomTitle(mainPath),
169→            ]);
170→            return {
171→              main: {
172→                path: mainPath,
173→                mtime: mainStats.mtime,
174→                agentType: 'claude',
175→                ...(mainTitle ? { customTitle: mainTitle } : {}),
176→              },
177→              subagent: subagentResult,
178→            };
179→          } catch {
180→            // 主 session 不存在，只返回 subagent
181→            return subagentResult;
182→          }
183→        }
184→        return subagentResult;
185→      }
186→    }
187→
188→    return null;
189→  }
190→
191→  /**
192→   * 判斷 ID 類型
193→   */
194→  private detectIdType(id: string): 'main' | 'subagent' | 'unknown' {
195→    // 完整 UUID 格式
196→    const uuidPattern =
197→      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
198→    // Subagent 格式：agent-{7hex} 或純 {7hex}
199→    const subagentPattern = /^(agent-)?[0-9a-f]{7}$/i;
200→
201→    if (uuidPattern.test(id)) return 'main';
202→    if (subagentPattern.test(id)) return 'subagent';
203→
204→    // 如果是 UUID 前綴（8位以上但不完整），視為主 session
205→    if (/^[0-9a-f]{8,35}$/i.test(id)) return 'main';
206→
207→    return 'unknown';
208→  }
209→
210→  /**
211→   * 從 subagent 路徑反推主 session 路徑
212→   * 路徑結構: {projectDir}/{sessionUUID}/subagents/agent-xxx.jsonl
213→   */
214→  private getMainSessionFromSubagent(subagentPath: string): string | null {
215→    const parts = subagentPath.split('/');
216→    const subagentsIdx = parts.lastIndexOf('subagents');
217→
218→    if (subagentsIdx === -1 || subagentsIdx < 2) return null;
219→
220→    const sessionUUID = parts[subagentsIdx - 1];
221→    const projectDir = parts.slice(0, subagentsIdx - 1).join('/');
222→
223→    // 主 session 在 projectDir 下，檔名為 sessionUUID.jsonl
224→    return join(projectDir, `${sessionUUID}.jsonl`);
225→  }
226→
227→  /**
228→   * 依 session ID 查找主 session
229→   */
230→  private async findMainBySessionId(
231→    sessionId: string,
232→    options: { project?: string }
233→  ): Promise<SessionFile | null> {
234→    const glob = new Glob('**/*.jsonl');
235→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
236→
237→    const uuidPattern =
238→      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
239→    const searchTerm = sessionId.toLowerCase();
240→
241→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
242→      const filename = file.split('/').pop() || '';
243→
244→      // 排除 subagent 檔案
245→      if (filename.startsWith('agent-')) continue;
246→
247→      // 只匹配 UUID 格式的檔案名
248→      if (!uuidPattern.test(filename)) continue;
249→
250→      // project filter
251→      if (options.project) {
252→        const pattern = options.project.toLowerCase();
253→        if (!file.toLowerCase().includes(pattern)) continue;
254→      }
255→
256→      const baseName = filename.replace(/\.jsonl$/, '').toLowerCase();
257→
258→      // 計算匹配優先級
259→      let priority = 0;
260→      if (baseName === searchTerm) {
261→        priority = 3; // 精確匹配
262→      } else if (baseName.startsWith(searchTerm)) {
263→        priority = 2; // 前綴匹配
264→      } else if (baseName.includes(searchTerm)) {
265→        priority = 1; // 包含匹配
266→      }
267→
268→      if (priority === 0) continue;
269→
270→      try {
271→        const stats = await stat(file);
272→        candidates.push({ path: file, mtime: stats.mtime, priority });
273→      } catch {
274→        // 忽略
275→      }
276→    }
277→
278→    if (candidates.length === 0) return null;
279→
280→    // 排序：優先級降序 > mtime 降序
281→    candidates.sort((a, b) => {
282→      if (b.priority !== a.priority) return b.priority - a.priority;
283→      return b.mtime.getTime() - a.mtime.getTime();
284→    });
285→
286→    const best = candidates[0];
287→    if (!best) return null;
288→
289→    const customTitle = await readCustomTitle(best.path);
290→    return {
291→      path: best.path,
292→      mtime: best.mtime,
293→      agentType: 'claude',
294→      ...(customTitle ? { customTitle } : {}),
295→    };
296→  }
