215→  /**
216→   * 找到 subagent 檔案
217→   * - 有 subagentId：用 UUID glob 在所有日期目錄查找
218→   * - 無 subagentId：從最新 session 掃描 subagent IDs，回傳最新的 subagent 檔案
219→   *
220→   * 已知限制：無 subagentId 時，findLatest() 不保證回傳主 session（可能回傳 subagent 檔案）。
221→   * 若 extractCodexSubagentIds 回傳空陣列，會回傳 null。
222→   */
223→  async findSubagent(options: {
224→    project?: string;
225→    subagentId?: string;
226→  }): Promise<SessionFile | null> {
227→    if (options.subagentId) {
228→      // 有 subagentId：用 UUID glob 精確查找
229→      return this._findSubagentById(options.subagentId, options.project);
230→    } else {
