278→  /**
279→   * 掃描所有 session，從最新的開始找第一個含 subagent IDs 的，回傳最新的 subagent 檔案
280→   *
281→   * 注意：findLatest() 不區分主 session 和 subagent session（依 mtime 排序）。
282→   * 此方法改為迭代所有候選 session，跳過不含 spawn_agent 事件的（通常是 subagent 本身）。
283→   */
284→  private async _findLatestSubagent(
285→    project?: string
286→  ): Promise<SessionFile | null> {
287→    const glob = new Glob('**/*.jsonl');
288→    const candidates: { path: string; mtime: Date }[] = [];
289→
290→    for await (const file of glob.scan({
291→      cwd: this._baseDir,
292→      absolute: true,
293→    })) {
294→      const filename = file.split('/').pop() || '';
295→      if (!filename.startsWith('rollout-')) continue;
296→
297→      if (project) {
298→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
299→      }
300→
301→      try {
302→        const stats = await stat(file);
303→        candidates.push({ path: file, mtime: stats.mtime });
304→      } catch {
305→        // 忽略無法讀取的檔案
306→      }
307→    }
308→
309→    if (candidates.length === 0) return null;
310→
311→    // 由新到舊排序，優先從最新的 session 找 subagent
312→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
313→
314→    for (const candidate of candidates) {
315→      const agentIds = await extractCodexSubagentIds(candidate.path);
316→      if (agentIds.length === 0) continue;
317→
318→      const dateDir = dirname(candidate.path);
319→      const subFiles = await buildCodexSubagentFiles(dateDir, agentIds);
320→      if (subFiles.length === 0) continue;
321→
322→      subFiles.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
323→      return subFiles[0] ?? null;
324→    }
325→
326→    return null;
327→  }
328→}
