  1→import { stat } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { basename, dirname, join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ParsedLine,
  8→  ParserOptions,
  9→  ProjectInfo,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import { truncateByLines, formatMultiline } from '../../utils/text.ts';
 13→import { formatToolUse } from '../../utils/format-tool.ts';
