1164→  const dateDir = dirname(sessionFile.path);
1165→
1166→  // 2. projectDir（super-follow 用），從 session_meta 取得 cwd
1167→  const codexAgent = new CodexAgent({ verbose: options.verbose });
1168→  const projectInfo = codexAgent.finder.getProjectInfo
1169→    ? await codexAgent.finder.getProjectInfo(sessionFile.path)
1170→    : null;
1171→  const projectDir = projectInfo?.projectDir ?? dateDir;
1172→
1173→  // 3. 掃描既有 subagent IDs
1174→  const existingIds = options.withSubagents
1175→    ? await extractCodexSubagentIds(sessionFile.path)
1176→    : [];
1177→
1178→  // 4. 建立監控檔案列表
1179→  const existingSubFiles =
1180→    options.withSubagents && existingIds.length > 0
1181→      ? await buildCodexSubagentFiles(dateDir, existingIds)
1182→      : [];
1183→
1184→  const files: WatchedFile[] = [
1185→    { path: sessionFile.path, label: MAIN_LABEL },
1186→    ...existingSubFiles.map((f) => {
1187→      // makeCodexAgentLabel 接受 UUID，不是路徑
1188→      const agentId = extractUUIDFromPath(f.path);
1189→      return { path: f.path, label: makeCodexAgentLabel(agentId) };
1190→    }),
1191→  ];
1192→
1193→  if (existingIds.length > 0) {
1194→    log(options.quiet, chalk.gray(`Found ${existingIds.length} subagent(s)`));
1195→  }
1196→  log(options.quiet, chalk.gray('---'));
1197→
1198→  // 5. Codex parser 無狀態，多 file 共用一個實例
1199→  const parser = codexAgent.parser;
1200→
1201→  // 6. PaneManager 初始化（Phase 2: --pane 支援）
1202→  let paneManager: PaneManager | null = null;
1203→  if (options.pane) {
1204→    const controller = createTerminalController();
1205→    if (controller.isAvailable()) {
1206→      paneManager = new PaneManager(
1207→        controller,
1208→        (agentId, _subagentPath) => {
1209→          const runtime = `"${process.argv[0]}"`;
1210→          const script = `"${process.argv[1]}"`;
1211→          return `${runtime} ${script} codex --subagent ${agentId} -q --no-pane`;
1212→        },
1213→        (msg) => log(options.quiet, chalk.gray(msg))
1214→      );
1215→    } else {
1216→      log(
1217→        options.quiet,
1218→        chalk.yellow('Warning: tmux not detected, --pane disabled')
1219→      );
1220→    }
1221→  }
1222→
1223→  const pm = paneManager;
1224→
1225→  // Codex label 用短 ID（如 019cc375-8a57），但 PaneManager 用完整 UUID 作 key
1226→  // 此映射讓 shouldOutput 能從短 ID 反查完整 UUID
1227→  const shortIdToFullId = new Map<string, string>();
1228→  function registerShortId(agentId: string): void {
1229→    const parts = agentId.split('-');
1230→    const shortId = `${parts[0]}-${(parts[4] ?? '').slice(0, 4)}`;
1231→    shortIdToFullId.set(shortId, agentId);
1232→  }
1233→
1234→  // pane 模式下：既有 subagent 加入 suppress set（完整 UUID v7），避免歷史內容污染 main pane
1235→  const suppressedForPane = new Set<string>();
1236→
1237→  /** 預填既有 subagent 路徑到 detector，同步短 ID 映射，並填充 suppressedForPane（若有 pane） */
1238→  function prefillExistingSubagents(
1239→    det: CodexSubagentDetector,
1240→    files: SessionFile[]
1241→  ): void {
1242→    for (const f of files) {
1243→      const uuid = extractUUIDFromPath(f.path);
1244→      if (pm) {
1245→        registerShortId(uuid);
1246→        suppressedForPane.add(uuid);
1247→      }
1248→      det.registerExistingAgent(uuid, f.path);
1249→    }

