1447→
1448→  // 建立 onLine handler 函數（單一 agent 用，與 Claude 多檔案的 createOnLineHandler 不同）
1449→  const makeSingleLineHandler =
1450→    (parser: LineParser) =>
1451→    (line: string): void => {
1452→      if (options.agentType === 'gemini') {
1453→        // Gemini 模式：parser 有狀態追蹤，每次只回傳一個部分
1454→        // 需要反覆呼叫直到沒有更多內容
1455→        let parsed = parser.parse(line);
1456→        while (parsed) {
1457→          console.log(formatter.format(parsed));
1458→          parsed = parser.parse(line);
1459→        }
1460→      } else {
1461→        // Codex JSONL 模式：每行一個事件，單次處理
1462→        const parsed = parser.parse(line);
1463→        if (parsed) {
1464→          console.log(formatter.format(parsed));
1465→        }
1466→      }
1467→    };
1468→
1469→  // 切換到新 session 的函數
1470→  const switchToSession = async (nextFile: SessionFile): Promise<void> => {
1471→    watcher.stop();
1472→    currentPath = nextFile.path;
1473→
1474→    log(
1475→      options.quiet,
1476→      chalk.gray(`--- Switched to ${basename(nextFile.path)} ---`)
1477→    );
1478→
1479→    // Gemini 需要重建 parser 以清除狀態（processedMessageIds 等）
1480→    if (options.agentType === 'gemini') {
1481→      const newAgent = new GeminiAgent({ verbose: options.verbose });
1482→      currentParser = newAgent.parser;
1483→    }
1484→
1485→    watcher = new FileWatcher();
1486→    await watcher.start(nextFile.path, {
1487→      follow: true,
1488→      pollInterval: options.sleepInterval,
1489→      initialLines: options.lines,
1490→      jsonMode: options.agentType === 'gemini',
1491→      onLine: makeSingleLineHandler(currentParser),
1492→      onError: (error) => {
1493→        console.error(chalk.red(`Error: ${error.message}`));
1494→      },
1495→    });
1496→  };
1497→
1498→  // 建立 super-follow 控制器（如果支援）
1499→  const superFollow =
1500→    options.autoSwitch && projectInfo && agent.finder.findLatestInProject
1501→      ? createSuperFollowController({
1502→          projectDir: projectInfo.projectDir,
1503→          getCurrentPath: () => currentPath,
1504→          onSwitch: switchToSession,
1505→          autoSwitch: true,
1506→          findLatestInProject: agent.finder.findLatestInProject.bind(
1507→            agent.finder
1508→          ),
1509→        })
1510→      : null;
1511→
1512→  // 處理中斷信號
1513→  process.on('SIGINT', () => {
1514→    log(options.quiet, chalk.gray('\nStopping...'));
1515→    superFollow?.stop();
1516→    watcher.stop();
1517→    process.exit(0);
1518→  });
1519→
1520→  // 開始監控
1521→  await watcher.start(sessionFile.path, {
1522→    follow: options.follow,
1523→    pollInterval: options.sleepInterval,
1524→    initialLines: options.lines,
1525→    // Gemini 使用完整 JSON 檔案格式，需要啟用 jsonMode
1526→    jsonMode: options.agentType === 'gemini',
1527→    onLine: makeSingleLineHandler(currentParser),
1528→    onError: (error) => {
1529→      console.error(chalk.red(`Error: ${error.message}`));
1530→    },
1531→  });
1532→
1533→  // 如果不是 follow 模式，結束程式
1534→  if (!options.follow) {
1535→    process.exit(0);
1536→  }
1537→
1538→  // 啟動 super-follow（如果啟用）
1539→  superFollow?.start();
1540→
1541→  // 保持程式運行
1542→  log(options.quiet, chalk.gray('Watching for changes... (Ctrl+C to stop)'));
1543→}
