 66→/**
 67→ * 解析 CLI 參數
 68→ */
 69→export function parseArgs(args: string[]): CliOptions {
 70→  const program = createProgram();
 71→  program.parse(args);
 72→
 73→  const agentTypeArg = program.args[0];
 74→  const sessionIdArg = program.args[1];
 75→  const opts = program.opts();
 76→
 77→  // 驗證 agent 類型
 78→  if (
 79→    agentTypeArg !== 'codex' &&
 80→    agentTypeArg !== 'claude' &&
 81→    agentTypeArg !== 'gemini'
 82→  ) {
 83→    console.error(
 84→      `Error: Invalid agent type "${agentTypeArg}". Use "codex", "claude", or "gemini".`
 85→    );
 86→    process.exit(1);
 87→  }
 88→
 89→  // subagent 選項對 claude 和 codex 有效
 90→  if (
 91→    opts.subagent !== undefined &&
 92→    agentTypeArg !== 'claude' &&
 93→    agentTypeArg !== 'codex'
 94→  ) {
 95→    console.error(
 96→      'Error: --subagent option is only available for "claude" and "codex" agent types.'
 97→    );
 98→    process.exit(1);
 99→  }
100→
101→  // --all preset 選項對 claude 和 codex 有效（需要在展開前驗證）
102→  if (opts.all && agentTypeArg !== 'claude' && agentTypeArg !== 'codex') {
103→    console.error(
104→      'Error: --all option is only available for "claude" and "codex" agent types.'
105→    );
106→    process.exit(1);
107→  }
108→
109→  // 展開 --all preset（只在選項未明確設定時才覆蓋）
110→  if (opts.all) {
111→    if (opts.verbose === undefined) opts.verbose = true;
112→    if (opts.withSubagents === undefined) opts.withSubagents = true;
113→    if (opts.autoSwitch === undefined) opts.autoSwitch = true;
114→  }
115→
116→  // 將 undefined 轉換為 false（對於非 preset 選項）
117→  const finalVerbose = opts.verbose ?? false;
118→  const finalInteractive = opts.interactive ?? false;
119→  let finalWithSubagents = opts.withSubagents ?? false;
120→  const finalAutoSwitch = opts.autoSwitch ?? false;
121→  const finalPane = opts.pane ?? false;
122→
123→  // interactive 選項對 claude 和 codex 有效
124→  if (
125→    finalInteractive &&
126→    agentTypeArg !== 'claude' &&
127→    agentTypeArg !== 'codex'
128→  ) {
129→    console.error(
130→      'Error: --interactive option is only available for "claude" and "codex" agent types.'
131→    );
132→    process.exit(1);
133→  }
134→
135→  // interactive 和 subagent 互斥
136→  if (finalInteractive && opts.subagent !== undefined) {
137→    console.error(
138→      'Error: --interactive and --subagent options cannot be used together.'
139→    );
140→    process.exit(1);
141→  }
142→
143→  // interactive 需要 follow 模式
144→  if (finalInteractive && !opts.follow) {
145→    console.error(
146→      'Error: --interactive requires --follow mode (cannot use with --no-follow).'
147→    );
148→    process.exit(1);
149→  }
150→
151→  // pane 選項對 claude 和 codex 有效
152→  if (finalPane && agentTypeArg !== 'claude' && agentTypeArg !== 'codex') {
153→    console.error(
154→      'Error: --pane option is only available for "claude" and "codex" agent types.'
155→    );
156→    process.exit(1);
157→  }
158→
159→  // pane 和 interactive 互斥
160→  if (finalPane && finalInteractive) {
161→    console.error(
162→      'Error: --pane and --interactive options cannot be used together.'
163→    );
164→    process.exit(1);
165→  }
166→
167→  // pane 和 subagent 互斥（pane 在多檔案監控模式，subagent 在單檔案模式）
168→  if (finalPane && opts.subagent !== undefined) {
169→    console.error(
170→      'Error: --pane and --subagent options cannot be used together.'
171→    );
172→    process.exit(1);
173→  }
174→
175→  // pane 需要 follow 模式
176→  if (finalPane && !opts.follow) {
177→    console.error(
178→      'Error: --pane requires --follow mode (cannot use with --no-follow).'
179→    );
180→    process.exit(1);
181→  }
182→
183→  // pane 自動啟用 withSubagents（subagent 偵測必須啟用才能開 pane）
184→  if (finalPane && !finalWithSubagents) {
185→    finalWithSubagents = true;
186→  }
187→
188→  // withSubagents 選項對 claude 和 codex 有效
189→  if (
190→    finalWithSubagents &&
191→    agentTypeArg !== 'claude' &&
192→    agentTypeArg !== 'codex'
193→  ) {
194→    console.error(
195→      'Error: --with-subagents option is only available for "claude" and "codex" agent types.'
196→    );
197→    process.exit(1);
198→  }
199→
200→  // sleepInterval 驗證
201→  if (
202→    opts.sleepInterval !== undefined &&
203→    (opts.sleepInterval < 100 || opts.sleepInterval > 60000)
204→  ) {
205→    console.error(
206→      'Error: --sleep-interval must be between 100 and 60000 milliseconds.'
207→    );
208→    process.exit(1);
209→  }
210→
211→  // lines 驗證
212→  if (opts.lines !== undefined && Number.isNaN(opts.lines)) {
213→    console.error('Error: --lines must be a valid number.');
214→    process.exit(1);
215→  }
216→
217→  return {
218→    agentType: agentTypeArg as AgentType,
219→    raw: opts.raw,
220→    project: opts.project,
221→    follow: opts.follow,
222→    verbose: finalVerbose,
223→    quiet: opts.quiet ?? false,
224→    sleepInterval: opts.sleepInterval ?? 500,
225→    lines: opts.lines,
226→    subagent: opts.subagent,
227→    interactive: finalInteractive,
228→    withSubagents: finalWithSubagents,
229→    autoSwitch: finalAutoSwitch,
230→    pane: finalPane,
231→    sessionId: sessionIdArg,
232→  };
233→}
