 23→/**
 24→ * Claude Code Session Finder
 25→ * 目錄結構: ~/.claude/projects/{encoded-path}/{UUID}.jsonl
 26→ */
 27→class ClaudeSessionFinder implements SessionFinder {
 28→  private baseDir: string;
 29→
 30→  constructor() {
 31→    this.baseDir = join(homedir(), '.claude', 'projects');
 32→  }
 33→
 34→  getBaseDir(): string {
 35→    return this.baseDir;
 36→  }
 37→
 38→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 39→    const glob = new Glob('**/*.jsonl');
 40→    const files: { path: string; mtime: Date }[] = [];
 41→
 42→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 43→      const filename = file.split('/').pop() || '';
 44→
 45→      // 排除 agent-* 開頭的檔案
 46→      if (filename.startsWith('agent-')) continue;
 47→
 48→      // 只匹配 UUID 格式的檔案名
 49→      const uuidPattern =
 50→        /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
 51→      if (!uuidPattern.test(filename)) continue;
 52→
 53→      // 如果有 project filter，做模糊比對
 54→      if (options.project) {
 55→        const pattern = options.project.toLowerCase();
 56→        // 對路徑做模糊比對（包含專案目錄名稱）
 57→        if (!file.toLowerCase().includes(pattern)) continue;
 58→      }
 59→
 60→      try {
 61→        const stats = await stat(file);
 62→        files.push({ path: file, mtime: stats.mtime });
 63→      } catch {
 64→        // 忽略無法讀取的檔案
 65→      }
 66→    }
 67→
 68→    if (files.length === 0) return null;
 69→
 70→    // 按修改時間排序，取最新的
 71→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 72→
 73→    const latest = files[0];
 74→    if (!latest) return null;
 75→
 76→    const customTitle = await readCustomTitle(latest.path);
 77→    return {
 78→      path: latest.path,
 79→      mtime: latest.mtime,
 80→      agentType: 'claude',
 81→      ...(customTitle ? { customTitle } : {}),
 82→    };
 83→  }
 84→
 85→  /**
 86→   * 找到 subagent 檔案
 87→   * 新結構: {sessionId}/subagents/agent-{7位hex}.jsonl
 88→   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
 89→   */
 90→  async findSubagent(options: {
 91→    project?: string;
 92→    subagentId?: string;
 93→  }): Promise<SessionFile | null> {
 94→    const { project, subagentId } = options;
 95→
 96→    // 決定 glob pattern（新結構：{UUID}/subagents/ 目錄下）
 97→    const pattern = subagentId
 98→      ? `**/*/subagents/agent-${subagentId}.jsonl`
 99→      : '**/*/subagents/agent-*.jsonl';
100→
101→    const glob = new Glob(pattern);
102→    const files: { path: string; mtime: Date }[] = [];
103→
104→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
105→      const filename = file.split('/').pop() || '';
106→
107→      // 驗證 subagent 檔名格式: agent-{7~40位十六進制}.jsonl
108→      const subagentPattern = /^agent-[0-9a-f]{7,40}\.jsonl$/i;
109→      if (!subagentPattern.test(filename)) continue;
110→
111→      // project filter
112→      if (project && !file.toLowerCase().includes(project.toLowerCase())) {
113→        continue;
114→      }
115→
116→      try {
117→        const stats = await stat(file);
118→        files.push({ path: file, mtime: stats.mtime });
119→      } catch {
120→        // 忽略無法讀取的檔案
121→      }
122→    }
123→
124→    if (files.length === 0) return null;
125→
126→    // 按修改時間排序，取最新的
127→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
128→    const latest = files[0];
129→    if (!latest) return null;
130→
131→    return {
132→      path: latest.path,
133→      mtime: latest.mtime,
134→      agentType: 'claude',
135→    };
136→  }
