257→/**
258→ * Gemini CLI JSON 解析器
259→ * 注意：Gemini 使用完整 JSON 檔案（非 JSONL），需要追蹤已處理的 messages
260→ */
261→class GeminiLineParser implements LineParser {
262→  private processedMessageIds = new Set<string>();
263→  /** 追蹤 gemini message 內部的處理進度：toolCalls index 和 content 是否已處理 */
264→  private currentMessageState: {
265→    messageId: string;
266→    toolCallIndex: number;
267→    contentProcessed: boolean;
268→  } | null = null;
269→  private verbose: boolean;
270→
271→  constructor(options: ParserOptions = { verbose: false }) {
272→    this.verbose = options.verbose;
273→  }
274→
275→  parse(line: string): ParsedLine | null {
276→    if (!line.trim()) return null;
277→
278→    try {
279→      // 嘗試解析為完整 JSON（整個 session 檔案內容）
280→      const data = JSON.parse(line);
281→
282→      // 如果是完整的 session JSON（有 messages 陣列）
283→      if (data.messages && Array.isArray(data.messages)) {
284→        return this.parseSessionJson(data);
285→      }
286→
287→      // 否則當作單行 JSON 處理
288→      return this.parseSingleMessage(data);
289→    } catch {
290→      return null;
291→    }
292→  }
293→
294→  /**
295→   * 解析完整 session JSON，逐個回傳 message 的各個部分
296→   * gemini 類型的 message 會被拆分成多個輸出（每個 toolCall 和 content）
297→   */
298→  private parseSessionJson(session: {
299→    sessionId?: string;
300→    messages: Array<{
301→      id: string;
302→      type: string;
303→      content: string;
304→      timestamp: string;
305→      tokens?: Record<string, number>;
306→      toolCalls?: Array<{
307→        name?: string;
308→        args?: Record<string, unknown>;
309→        status?: string;
310→      }>;
311→    }>;
312→  }): ParsedLine | null {
313→    const messages = session.messages || [];
314→
315→    // 如果正在處理某個 gemini message 的內部狀態
316→    if (this.currentMessageState) {
317→      const msg = messages.find(
318→        (m) => m.id === this.currentMessageState!.messageId
319→      );
320→      if (msg) {
321→        const result = this.processGeminiMessagePart(msg);
322→        if (result) return result;
323→      }
324→      // 當前 message 處理完畢
325→      this.currentMessageState = null;
326→    }
327→
328→    // 找到下一個未處理的 message
329→    const nextMessage = messages.find(
330→      (m) => !this.processedMessageIds.has(m.id)
331→    );
332→    if (!nextMessage) return null;
333→
334→    // user 類型直接輸出
335→    if (nextMessage.type === 'user') {
336→      this.processedMessageIds.add(nextMessage.id);
337→      const content = nextMessage.content || '';
338→      if (!content.trim()) {
339→        return this.parseSessionJson(session);
340→      }
341→      const preview = truncateByLines(content, { verbose: this.verbose });
342→      return {
343→        type: 'user',
344→        timestamp: nextMessage.timestamp,
345→        raw: nextMessage,
346→        formatted: formatMultiline(preview),
347→      };
348→    }
349→
350→    // gemini 類型需要拆分處理
351→    if (nextMessage.type === 'gemini') {
352→      this.processedMessageIds.add(nextMessage.id);
353→      // 初始化內部狀態
354→      this.currentMessageState = {
355→        messageId: nextMessage.id,
356→        toolCallIndex: 0,
357→        contentProcessed: false,
358→      };
359→      const result = this.processGeminiMessagePart(nextMessage);
360→      if (result) return result;
361→      // 如果沒有內容，處理下一個 message
362→      this.currentMessageState = null;
363→      return this.parseSessionJson(session);
364→    }
365→
366→    // 其他類型
367→    this.processedMessageIds.add(nextMessage.id);
368→    const content = nextMessage.content || '';
369→    const preview = truncateByLines(content, { verbose: this.verbose });
370→    return {
371→      type: nextMessage.type,
372→      timestamp: nextMessage.timestamp,
373→      raw: nextMessage,
374→      formatted: formatMultiline(preview),
375→    };
376→  }
377→
378→  /**
379→   * 處理 gemini message 的下一個部分（toolCall 或 content）
380→   */
381→  private processGeminiMessagePart(msg: {
382→    id: string;
383→    timestamp: string;
384→    content: string;
385→    toolCalls?: Array<{
386→      name?: string;
387→      args?: Record<string, unknown>;
388→      status?: string;
389→    }>;
390→  }): ParsedLine | null {
391→    if (!this.currentMessageState) return null;
392→
393→    const toolCalls = msg.toolCalls || [];
394→
395→    // 先處理 toolCalls
396→    if (this.currentMessageState.toolCallIndex < toolCalls.length) {
397→      const tc = toolCalls[this.currentMessageState.toolCallIndex];
398→      this.currentMessageState.toolCallIndex++;
399→      if (tc) {
400→        const status = tc.status === 'error' ? ' ❌' : '';
401→        const toolName = tc.name || 'unknown';
402→        return {
403→          type: 'function_call',
404→          timestamp: msg.timestamp,
405→          raw: tc,
406→          formatted:
407→            formatToolUse(toolName, tc.args, { verbose: this.verbose }) +
408→            status,
409→          toolName,
410→        };
411→      }
412→    }
413→
414→    // 然後處理 content
415→    if (!this.currentMessageState.contentProcessed) {
416→      this.currentMessageState.contentProcessed = true;
417→      const content = msg.content || '';
418→      if (content.trim()) {
419→        const preview = truncateByLines(content, { verbose: this.verbose });
420→        return {
421→          type: 'gemini',
422→          timestamp: msg.timestamp,
423→          raw: msg,
424→          formatted: formatMultiline(preview),
425→        };
426→      }
427→    }
428→
429→    return null;
430→  }
431→
432→  /**
433→   * 解析單一 message（非 session JSON 的情況，較少見）
434→   */
435→  private parseSingleMessage(data: Record<string, unknown>): ParsedLine | null {
436→    const type = (data.type as string) || 'unknown';
437→    const timestamp = (data.timestamp as string) || '';
438→    const content = (data.content as string) || '';
439→
440→    if (!content.trim()) return null;
441→
442→    const preview = truncateByLines(content, { verbose: this.verbose });
443→    return {
444→      type,
445→      timestamp,
446→      raw: data,
447→      formatted: formatMultiline(preview),
448→    };
449→  }
450→}
