330→/**
331→ * Codex JSONL 解析器
332→ */
333→class CodexLineParser implements LineParser {
334→  private verbose: boolean;
335→
336→  constructor(options: ParserOptions = { verbose: false }) {
337→    this.verbose = options.verbose;
338→  }
339→
340→  parse(line: string): ParsedLine | null {
341→    if (!line.trim()) return null;
342→
343→    try {
344→      const data = JSON.parse(line);
345→      const timestamp = data.timestamp || '';
346→      const formatted = this.format(data);
347→
348→      // 空內容不輸出
349→      if (!formatted) return null;
350→
351→      // 決定顯示類型
352→      const type = this.getDisplayType(data);
353→
354→      // 取得 tool name（僅 function_call 類型）
355→      const toolName = this.getToolName(data);
356→
357→      return {
358→        type,
359→        timestamp,
360→        raw: data,
361→        formatted,
362→        ...(toolName && { toolName }),
363→      };
364→    } catch {
365→      return null;
366→    }
367→  }
368→
369→  /**
370→   * 取得 tool 名稱（僅 function_call 類型）
371→   */
372→  private getToolName(data: Record<string, unknown>): string | undefined {
373→    const type = data.type as string;
374→    if (type !== 'response_item') return undefined;
375→
376→    const payload = data.payload as Record<string, unknown>;
377→    if (payload.type !== 'function_call') return undefined;
378→
379→    return payload.name as string | undefined;
380→  }
381→
382→  /**
383→   * 根據資料內容決定顯示類型
384→   */
385→  private getDisplayType(data: Record<string, unknown>): string {
386→    const type = data.type as string;
387→
388→    if (type === 'session_meta') return 'session_meta';
389→
390→    if (type === 'response_item') {
391→      const payload = data.payload as Record<string, unknown>;
392→      const subType = payload.type as string;
393→
394→      if (subType === 'message') {
395→        const role = payload.role as string;
396→        return role || 'message';
397→      }
398→      if (subType === 'function_call') return 'function_call';
399→      if (subType === 'function_call_output') return 'output';
400→      if (subType === 'reasoning') return 'reasoning';
401→    }
402→
403→    return type || 'unknown';
404→  }
405→
406→  private format(data: Record<string, unknown>): string {
407→    const type = data.type as string;
408→
409→    switch (type) {
410→      case 'session_meta': {
411→        const payload = data.payload as Record<string, unknown>;
412→        return `Session: ${payload.cwd || 'unknown'} (v${payload.cli_version || '?'})`;
413→      }
414→
415→      case 'response_item': {
416→        const payload = data.payload as Record<string, unknown>;
417→        const subType = payload.type as string;
418→
419→        switch (subType) {
420→          case 'message': {
421→            const _role = payload.role as string;
422→            const content = payload.content as Array<{
423→              type: string;
424→              text?: string;
425→            }>;
426→            const text =
427→              content?.find(
428→                (c) => c.type === 'input_text' || c.type === 'output_text'
429→              )?.text || '';
430→            if (!text.trim()) return '';
431→            const preview = truncateByLines(text, { verbose: this.verbose });
432→            // 不再重複顯示 role，由 pretty-formatter 處理
433→            return formatMultiline(preview);
434→          }
435→
436→          case 'function_call': {
437→            const name = payload.name as string;
438→            const argsStr = payload.arguments as string;
439→            let args: Record<string, unknown> = {};
440→            try {
441→              args = JSON.parse(argsStr);
442→            } catch {
443→              /* ignore */
444→            }
445→            return formatToolUse(name, args, { verbose: this.verbose });
446→          }
447→
448→          case 'function_call_output': {
449→            const outputStr = payload.output as string;
450→            let output: { output?: string; metadata?: { exit_code?: number } } =
451→              {};
452→            try {
453→              output = JSON.parse(outputStr);
454→            } catch {
455→              /* ignore */
456→            }
457→            const exitCode = output.metadata?.exit_code;
458→            const content = output.output || '';
459→            // 沒內容且 exit code 正常就不顯示
460→            if (!content && (exitCode === undefined || exitCode === 0))
461→              return '';
462→            const exitInfo =
463→              exitCode !== undefined && exitCode !== 0
464→                ? ` (exit: ${exitCode})`
465→                : '';
466→            if (!content) return `[OUTPUT${exitInfo}]`;
467→            const preview = truncateByLines(content, { verbose: this.verbose });
468→            return `${exitInfo ? `[exit: ${exitCode}]` : ''}${formatMultiline(preview)}`;
469→          }
470→
471→          case 'reasoning': {
472→            const summary = payload.summary as
473→              | Array<{ type: string; text?: string }>
474→              | undefined;
475→            const text =
476→              summary?.find((s) => s.type === 'summary_text')?.text || '';
477→            if (!text) return '';
478→            const preview = truncateByLines(text, { verbose: this.verbose });
479→            return preview;
480→          }
481→
482→          // 忽略的子類型
483→          case 'ghost_snapshot':
484→            return '';
485→
486→          default:
487→            return '';
488→        }
489→      }
490→
491→      case 'event_msg': {
492→        const payload = data.payload as Record<string, unknown>;
493→        const eventType = payload.type as string;
494→
495→        switch (eventType) {
496→          case 'token_count': {
497→            // 略過 token 統計，太 noisy
498→            return '';
499→          }
500→
501→          case 'agent_reasoning': {
502→            // 與 response_item.reasoning 重複，略過
503→            return '';
504→          }
505→
506→          // 略過其他事件
507→          default:
508→            return '';
509→        }
510→      }
511→
512→      // 略過 turn_context
513→      case 'turn_context':
514→        return '';
515→
516→      default:
517→        return '';
518→    }
519→  }
520→}
