  1→import chalk from 'chalk';
  2→
  3→export interface TruncateOptions {
  4→  /** 是否啟用 verbose 模式（不截斷） */
  5→  verbose?: boolean;
  6→  /** 前段保留字數，預設 100 */
  7→  headLength?: number;
  8→  /** 後段保留字數，預設 100 */
  9→  tailLength?: number;
 10→}
 11→
 12→/**
 13→ * 截斷文字，保留前後段落（字元計算）
 14→ * 格式: "前100字\n\n... (truncated) ...\n\n後100字"
 15→ */
 16→export function truncate(text: string, options: TruncateOptions = {}): string {
 17→  const { verbose = false, headLength = 100, tailLength = 100 } = options;
 18→
 19→  // verbose 模式不截斷
 20→  if (verbose) return text;
 21→
 22→  const threshold = headLength + tailLength + 10;
 23→  if (text.length <= threshold) return text;
 24→
 25→  const head = text.slice(0, headLength);
 26→  const tail = text.slice(-tailLength);
 27→  const omitted = text.length - headLength - tailLength;
 28→  const truncateMsg = chalk.yellow(`... (${omitted} chars omitted) ...`);
 29→
 30→  return `${head}\n\n${truncateMsg}\n\n${tail}`;
 31→}
 32→
 33→export interface TruncateByLinesOptions {
 34→  /** 是否啟用 verbose 模式（不截斷） */
 35→  verbose?: boolean;
 36→  /** 前段保留行數，預設 10 */
 37→  headLines?: number;
 38→  /** 後段保留行數，預設 10 */
 39→  tailLines?: number;
 40→}
 41→
 42→/**
 43→ * 截斷文字，保留前後行數（行數計算）
 44→ * 格式: "前10行\n\n... (N lines omitted) ...\n\n後10行"
 45→ */
 46→export function truncateByLines(
 47→  text: string,
 48→  options: TruncateByLinesOptions = {}
 49→): string {
 50→  const { verbose = false, headLines = 10, tailLines = 10 } = options;
 51→
 52→  // verbose 模式不截斷
 53→  if (verbose) return text;
 54→
 55→  const lines = text.split('\n');
 56→  const threshold = headLines + tailLines + 2;
 57→  if (lines.length <= threshold) return text;
 58→
 59→  const head = lines.slice(0, headLines);
 60→  const tail = lines.slice(-tailLines);
 61→  const omitted = lines.length - headLines - tailLines;
 62→  const truncateMsg = chalk.yellow(`... (${omitted} lines omitted) ...`);
 63→
 64→  return [...head, '', truncateMsg, '', ...tail].join('\n');
 65→}
 66→
 67→/**
 68→ * 將 content 轉為字串（處理物件/陣列情況）
 69→ */
 70→export function contentToString(content: unknown): string {
 71→  if (typeof content === 'string') return content;
 72→  if (content === null || content === undefined) return '';
 73→
 74→  if (Array.isArray(content)) {
 75→    return content
 76→      .map((item) => {
 77→        if (typeof item === 'string') return item;
 78→        if (item && typeof item === 'object') {
 79→          // 處理 { type: 'text', text: '...' } 格式
 80→          if ('text' in item && typeof item.text === 'string') return item.text;
 81→          // 處理 { type: 'tool_result', content: '...' } 格式
 82→          if ('content' in item && typeof item.content === 'string')
 83→            return item.content;
 84→          // 處理其他 type
 85→          if ('type' in item) return `[${item.type}]`;
 86→        }
 87→        return '';
 88→      })
 89→      .filter(Boolean)
 90→      .join(' ');
 91→  }
 92→
 93→  // 物件情況
 94→  if (typeof content === 'object') {
 95→    const obj = content as Record<string, unknown>;
 96→    if ('text' in obj && typeof obj.text === 'string') return obj.text;
 97→    if ('content' in obj && typeof obj.content === 'string') return obj.content;
 98→    return JSON.stringify(content);
 99→  }
100→
101→  return String(content);
102→}
103→
104→/**
105→ * 格式化多行內容
106→ * 單行 → 直接回傳 " content"
107→ * 多行 → 換行後每行加 4 空格縮排
108→ */
109→export function formatMultiline(
110→  content: string,
111→  indent: string = '    '
112→): string {
113→  if (!content.includes('\n')) {
114→    return ` ${content}`;
115→  }
116→
117→  const lines = content.split('\n');
118→  const indentedLines = lines.map((line) => `${indent}${line}`);
119→  return `\n${indentedLines.join('\n')}`;
120→}
