260→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
261→ */
262→async function startClaudeMultiWatch(
263→  sessionFile: SessionFile,
264→  formatter: Formatter,
265→  options: CliOptions,
266→  initialSubagent: SessionFile | null = null
267→): Promise<void> {
268→  const projectDir = dirname(sessionFile.path);
269→  let subagentsDir = getSubagentsDir(sessionFile.path);
270→
271→  // 建立監控檔案列表（主 session）
272→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
273→
274→  // 只有在 withSubagents 為 true 時才掃描 subagent
275→  const existingAgentIds = new Set<string>();
276→  if (options.withSubagents) {
277→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
278→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
279→    for (const id of dirAgentIds) {
280→      existingAgentIds.add(id);
281→    }
282→
283→    // 如果有從 sessionId 指定的 subagent，確保它被加入
284→    if (initialSubagent) {
285→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
286→        /^agent-/,
287→        ''
288→      );
289→      existingAgentIds.add(initialAgentId);
290→    }
291→
292→    const existingSubagentFiles = await buildSubagentFiles(
293→      subagentsDir,
294→      existingAgentIds
295→    );
296→    for (const { agentId, path } of existingSubagentFiles) {
297→      files.push({ path, label: makeAgentLabel(agentId) });
298→    }
299→
300→    if (existingAgentIds.size > 0) {
301→      log(
302→        options.quiet,
303→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
304→      );
305→    }
306→  }
307→  log(options.quiet, chalk.gray('---'));
308→
309→  // 為每個來源建立獨立的 parser
310→  let parsers = new Map<string, LineParser>();
311→  for (const file of files) {
312→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
313→    parsers.set(file.label, parserAgent.parser);
314→  }
315→
316→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
317→  if (!options.follow && options.withSubagents && files.length > 1) {
318→    await outputTimeSorted(files, parsers, formatter, options);
319→    process.exit(0);
320→  }
321→
322→  let multiWatcher = new MultiFileWatcher();
323→
324→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
325→  let paneManager: PaneManager | null = null;
326→  if (options.pane) {
327→    const controller = createTerminalController();
328→    if (controller.isAvailable()) {
329→      paneManager = new PaneManager(
330→        controller,
331→        (agentId, _subagentPath) => {
332→          // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
333→          // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
334→          const runtime = `"${process.argv[0]}"`;
335→          const script = `"${process.argv[1]}"`;
336→          return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
337→        },
338→        (msg) => log(options.quiet, chalk.gray(msg))
339→      );
340→    } else {
341→      log(
342→        options.quiet,
343→        chalk.yellow('Warning: tmux not detected, --pane disabled')
344→      );
345→    }
346→  }
347→
348→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
349→  const pm = paneManager; // 閉包捕獲，不受外部重賦值影響
350→  const openPaneForSubagent = pm
351→    ? (agentId: string, subagentPath: string, description?: string) => {
352→        pm.openPane(agentId, subagentPath, description).catch((err) => {
353→          log(
354→            options.quiet,
355→            chalk.yellow(`[pane] Failed to open pane: ${err}`)
356→          );
357→        });
358→      }
359→    : undefined;
360→
361→  const onSubagentDone = pm
362→    ? (agentId: string) => {
363→        const subagentPath = buildSubagentPath(subagentsDir, agentId);
364→
365→        // 先讀取並輸出最後的 assistant 訊息，再關閉 pane
366→        (async () => {
367→          try {
368→            const parts = await readLastAssistantMessage(
369→              subagentPath,
370→              options.verbose
371→            );
372→            const label = makeAgentLabel(agentId);
373→            for (const part of parts) {
374→              part.sourceLabel = label;
375→              console.log(formatter.format(part));
376→            }
377→          } catch {
378→            // 讀取失敗不影響 pane 關閉
379→          } finally {
380→            await pm.closePaneByAgentId(agentId);
381→          }
382→        })().catch(() => {});
383→      }
384→    : undefined;
385→
386→  const hasPaneCallback = pm
387→    ? (agentId: string) => pm.hasPaneForAgent(agentId)
388→    : undefined;
389→
390→  // pane 模式下，進入時既有 subagent 加入 suppress set，避免歷史內容污染 main pane
391→  const suppressedForPane = pm ? new Set(existingAgentIds) : new Set<string>();
392→
393→  const shouldOutput = pm
394→    ? (label: string) => {
395→        if (label === MAIN_LABEL) return true;
396→        const agentId = extractAgentIdFromLabel(label);
397→        if (suppressedForPane.has(agentId)) return false;
398→        return !pm.hasPaneForAgent(agentId);
399→      }
400→    : undefined;
401→
402→  // 建立 SubagentDetector（整合 early detection 和 fallback detection）
403→  let detector = new SubagentDetector(existingAgentIds, {
404→    subagentsDir,
405→    output: new ConsoleOutputHandler(),
406→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
407→    session: new NoOpSessionHandler(),
408→    enabled: options.follow && options.withSubagents,
409→    onNewSubagent: openPaneForSubagent,
410→    onSubagentEnter: openPaneForSubagent,
411→    onSubagentDone,
412→    hasPane: hasPaneCallback,
413→  });
414→  detector.startDirectoryWatch();
415→
416→  // ========== Non-Interactive Super-Follow ==========
417→  let currentSessionPath = sessionFile.path;
418→
419→  const switchToSession = async (
420→    nextSessionFile: SessionFile
421→  ): Promise<void> => {
422→    // 停止現有監控
423→    detector?.stop();
424→    multiWatcher.stop();
425→
426→    // 更新當前 session 路徑
427→    currentSessionPath = nextSessionFile.path;
428→
429→    // 重新初始化監控
430→    const newSessionId = basename(nextSessionFile.path, '.jsonl');
431→    const newSubagentsDir = getSubagentsDir(nextSessionFile.path);
432→
433→    const newFiles: WatchedFile[] = [
434→      { path: nextSessionFile.path, label: MAIN_LABEL },
435→    ];
436→    const newExistingAgentIds = new Set<string>();
437→
438→    // 掃描現有的 subagents
439→    if (options.withSubagents) {
440→      const dirAgentIds = await scanForNewSubagents(newSubagentsDir, new Set());
441→      for (const id of dirAgentIds) {
442→        newExistingAgentIds.add(id);
443→      }
444→
445→      const existingSubagentFiles = await buildSubagentFiles(
446→        newSubagentsDir,
447→        newExistingAgentIds
448→      );
449→      for (const { agentId, path } of existingSubagentFiles) {
450→        newFiles.push({ path, label: makeAgentLabel(agentId) });
451→      }
452→
453→      if (newExistingAgentIds.size > 0) {
454→        log(
455→          options.quiet,
456→          chalk.gray(`Found ${newExistingAgentIds.size} subagent(s)`)
457→        );
458→      }
459→    }

  1→import { watch, type FSWatcher } from 'node:fs';
  2→import { stat } from 'node:fs/promises';
  3→
  4→export interface WatchOptions {
  5→  follow: boolean;
  6→  onLine: (line: string) => void;
  7→  onError?: (error: Error) => void;
  8→  /** JSON 模式：不分割行，把整個檔案當作一個整體傳給 onLine */
  9→  jsonMode?: boolean;
 10→  /** Polling interval in milliseconds (default: 500) */
 11→  pollInterval?: number;
 12→  /** Number of initial lines to show (default: all) */
 13→  initialLines?: number;
 14→}
 15→
 16→/**
 17→ * 檔案監控器 - 實作 tail -f 效果
 18→ */
 19→export class FileWatcher {
 20→  private watcher: FSWatcher | null = null;
 21→  private processedLines = 0;
 22→  private isWatching = false;
 23→  private jsonMode = false;
 24→  private lastContentHash = '';
 25→  private lastMtimeMs = 0;
 26→  private lastSize = 0;
 27→  private filePath: string | null = null;
 28→  private options: WatchOptions | null = null;
 29→  private isRestarting = false;
 30→  private pollTimer: ReturnType<typeof setInterval> | null = null;
 31→  private isPolling = false;
 32→  private pollInterval = 500;
 33→  private isFirstRead = true;
 34→  // 競態條件防護：isProcessing 和 pending 標誌
 35→  private isProcessing = false;
 36→  private pendingRead = false;
 37→
 38→  /**
 39→   * 開始監控檔案
 40→   */
 41→  async start(filePath: string, options: WatchOptions): Promise<void> {
 42→    this.jsonMode = options.jsonMode || false;
 43→    this.filePath = filePath;
 44→    this.options = options;
 45→    this.pollInterval = options.pollInterval || 500;
 46→    this.isFirstRead = true;
 47→
 48→    // 初始讀取現有內容（直接呼叫，不需排程）
 49→    await this.readAndProcess(filePath, options.onLine);
 50→    await this.updateMtime(filePath);
 51→
 52→    // 如果需要持續監控
 53→    if (options.follow) {
 54→      this.isWatching = true;
 55→      this.startWatcher();
 56→      this.startPolling();
 57→    }
 58→  }
 59→
 60→  /**
 61→   * 排程讀取操作（防止競態條件）
 62→   * 如果正在處理，設為 pending 並返回
 63→   * 處理完成後如果 pending 為 true，再執行一次
 64→   */
 65→  private async scheduleRead(): Promise<void> {
 66→    if (!this.filePath || !this.options) return;
 67→
 68→    if (this.isProcessing) {
 69→      this.pendingRead = true;
 70→      return;
 71→    }
 72→
 73→    this.isProcessing = true;
 74→    this.pendingRead = false;
 75→
 76→    try {
 77→      await this.readAndProcess(this.filePath, this.options.onLine);
 78→      await this.updateMtime(this.filePath);
 79→
 80→      // 處理完成後，如果有 pending 請求，再執行一次
 81→      if (this.pendingRead) {
 82→        this.pendingRead = false;
 83→        await this.scheduleRead();
 84→      }
 85→    } catch (error) {
 86→      this.options.onError?.(error as Error);
 87→    } finally {
 88→      this.isProcessing = false;
 89→    }
 90→  }
 91→
 92→  /**
 93→   * 讀取並處理檔案內容
 94→   */
 95→  private async readAndProcess(
 96→    filePath: string,
 97→    onLine: (line: string) => void
 98→  ): Promise<void> {
 99→    const file = Bun.file(filePath);
100→    const content = await file.text();
101→
102→    if (this.jsonMode) {
103→      // JSON 模式：把整個檔案當作一個整體
104→      // 使用簡單的 hash 來檢測內容是否有變化
105→      const contentHash = Bun.hash(content).toString();
106→      if (contentHash !== this.lastContentHash) {
107→        this.lastContentHash = contentHash;
108→        onLine(content);
109→      }
110→    } else {
111→      // JSONL 模式：按行分割
112→      const lines = content.split('\n').filter(Boolean);
113→
114→      // 檔案被截斷或重寫時，重置已處理行數
115→      if (lines.length < this.processedLines) {
116→        this.processedLines = 0;
117→      } else if (lines.length <= this.processedLines) {
118→        const contentHash = Bun.hash(content).toString();
119→        if (this.lastContentHash && this.lastContentHash !== contentHash) {
120→          this.processedLines = 0;
121→        }
122→        this.lastContentHash = contentHash;
123→      }
124→
125→      // 處理 initialLines 選項
126→      let linesToProcess: string[];
127→      if (this.isFirstRead && this.options?.initialLines !== undefined) {
128→        const n = this.options.initialLines;
129→
130→        if (n < 0) {
131→          linesToProcess = lines; // 負數：全部
132→        } else if (n === 0) {
133→          linesToProcess = []; // 零：無
134→        } else if (n >= lines.length) {
135→          linesToProcess = lines; // 超出：全部
136→        } else {
137→          linesToProcess = lines.slice(-n); // 正常：最後 N 行
138→        }
139→      } else {
140→        linesToProcess = lines.slice(this.processedLines);
141→      }
142→
143→      for (const line of linesToProcess) {
144→        onLine(line);
145→      }
146→
147→      this.processedLines = lines.length;
148→      this.isFirstRead = false;
149→      if (lines.length > 0) {
150→        this.lastContentHash = Bun.hash(content).toString();
151→      }
152→    }
153→  }
154→
155→  /**
156→   * 停止監控
157→   */
158→  stop(): void {
159→    this.isWatching = false;
160→    this.watcher?.close();
161→    this.watcher = null;
162→    this.isRestarting = false;
163→    this.stopPolling();
164→  }
165→
166→  private startWatcher(): void {
167→    if (!this.filePath || !this.options) return;
168→
169→    this.watcher = watch(this.filePath, async (eventType) => {
170→      if (!this.isWatching || !this.options || !this.filePath) return;
171→
172→      if (eventType === 'rename') {
173→        await this.restartWatcher();
174→        return;
175→      }
176→
177→      if (eventType === 'change') {
178→        // 使用 scheduleRead 避免與 polling 競態
179→        await this.scheduleRead();
180→      }
181→    });
182→
183→    this.watcher.on('error', (error) => {
184→      this.options?.onError?.(error);
185→    });
186→  }
187→
188→  private async restartWatcher(): Promise<void> {
189→    if (this.isRestarting || !this.options || !this.filePath) return;
190→    this.isRestarting = true;
191→
192→    this.watcher?.close();
193→    this.watcher = null;
194→
195→    // 檔案可能被原子替換，需重置狀態避免漏讀
196→    this.processedLines = 0;
197→    this.lastContentHash = '';
198→    this.isFirstRead = false; // 重啟不算首次讀取
199→
200→    // 使用 scheduleRead 避免與 polling 競態
201→    await this.scheduleRead();
202→
203→    if (this.isWatching) {
204→      this.startWatcher();
205→    }
206→
207→    this.isRestarting = false;
208→  }
209→
210→  private startPolling(): void {
211→    if (this.isPolling || !this.filePath || !this.options) return;
212→    this.isPolling = true;
213→
214→    this.pollTimer = setInterval(async () => {
215→      if (!this.isWatching || !this.filePath || !this.options) return;
216→      try {
217→        const stats = await stat(this.filePath);
218→        // 檢查 mtime 或 size 是否有變化
219→        if (
220→          stats.mtimeMs !== this.lastMtimeMs ||
221→          stats.size !== this.lastSize
222→        ) {
223→          // 使用 scheduleRead 避免與 fs.watch 競態
224→          await this.scheduleRead();
225→        }
226→      } catch {
227→        // ignore
228→      }
229→    }, this.pollInterval);
230→  }
231→
232→  private stopPolling(): void {
233→    if (this.pollTimer) {
234→      clearInterval(this.pollTimer);
235→      this.pollTimer = null;
236→    }
237→    this.isPolling = false;
238→  }
239→
240→  private async updateMtime(filePath: string): Promise<void> {
241→    try {
242→      const stats = await stat(filePath);
243→      this.lastMtimeMs = stats.mtimeMs;
244→      this.lastSize = stats.size;
245→    } catch {
246→      // ignore
247→    }
248→  }
249→}
250→

1427→async function startSingleWatch(
1428→  agent: Agent,
1429→  sessionFile: SessionFile,
1430→  formatter: Formatter,
1431→  options: CliOptions
1432→): Promise<void> {
1433→  log(options.quiet, chalk.gray('---'));
1434→
1435→  // 取得專案資訊（用於 auto-switch）
1436→  const projectInfo =
1437→    options.autoSwitch && agent.finder.getProjectInfo
1438→      ? await agent.finder.getProjectInfo(sessionFile.path)
1439→      : null;
