import chalk from 'chalk';

export interface TruncateOptions {
  /** 是否啟用 verbose 模式（不截斷） */
  verbose?: boolean;
  /** 前段保留字數，預設 100 */
  headLength?: number;
  /** 後段保留字數，預設 100 */
  tailLength?: number;
}

/**
 * 截斷文字，保留前後段落（字元計算）
 * 格式: "前100字\n\n... (truncated) ...\n\n後100字"
 */
export function truncate(text: string, options: TruncateOptions = {}): string {
  const { verbose = false, headLength = 100, tailLength = 100 } = options;

  // verbose 模式不截斷
  if (verbose) return text;

  const threshold = headLength + tailLength + 10;
  if (text.length <= threshold) return text;

  const head = text.slice(0, headLength);
  const tail = text.slice(-tailLength);
  const omitted = text.length - headLength - tailLength;
  const truncateMsg = chalk.yellow(`... (${omitted} chars omitted) ...`);

  return `${head}\n\n${truncateMsg}\n\n${tail}`;
}

export interface TruncateByLinesOptions {
  /** 是否啟用 verbose 模式（不截斷） */
  verbose?: boolean;
  /** 前段保留行數，預設 10 */
  headLines?: number;
  /** 後段保留行數，預設 10 */
  tailLines?: number;
}

/**
 * 截斷文字，保留前後行數（行數計算）
 * 格式: "前10行\n\n... (N lines omitted) ...\n\n後10行"
 */
export function truncateByLines(
  text: string,
  options: TruncateByLinesOptions = {}
): string {
  const { verbose = false, headLines = 10, tailLines = 10 } = options;

  // verbose 模式不截斷
  if (verbose) return text;

  const lines = text.split('\n');
  const threshold = headLines + tailLines + 2;
  if (lines.length <= threshold) return text;

  const head = lines.slice(0, headLines);
  const tail = lines.slice(-tailLines);
  const omitted = lines.length - headLines - tailLines;
  const truncateMsg = chalk.yellow(`... (${omitted} lines omitted) ...`);

  return [...head, '', truncateMsg, '', ...tail].join('\n');
}

/**
 * 將 content 轉為字串（處理物件/陣列情況）
 */
export function contentToString(content: unknown): string {
  if (typeof content === 'string') return content;
  if (content === null || content === undefined) return '';

  if (Array.isArray(content)) {
    return content
      .map((item) => {
        if (typeof item === 'string') return item;
        if (item && typeof item === 'object') {
          // 處理 { type: 'text', text: '...' } 格式
          if ('text' in item && typeof item.text === 'string') return item.text;
          // 處理 { type: 'tool_result', content: '...' } 格式
          if ('content' in item && typeof item.content === 'string')
            return item.content;
          // 處理其他 type
          if ('type' in item) return `[${item.type}]`;
        }
        return '';
      })
      .filter(Boolean)
      .join(' ');
  }

  // 物件情況
  if (typeof content === 'object') {
    const obj = content as Record<string, unknown>;
    if ('text' in obj && typeof obj.text === 'string') return obj.text;
    if ('content' in obj && typeof obj.content === 'string') return obj.content;
    return JSON.stringify(content);
  }

  return String(content);
}

/**
 * 格式化多行內容
 * 單行 → 直接回傳 " content"
 * 多行 → 換行後每行加 4 空格縮排
 */
export function formatMultiline(
  content: string,
  indent: string = '    '
): string {
  if (!content.includes('\n')) {
    return ` ${content}`;
  }

  const lines = content.split('\n');
  const indentedLines = lines.map((line) => `${indent}${line}`);
  return `\n${indentedLines.join('\n')}`;
}

