  3→import { dirname, join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ParsedLine,
  8→  ParserOptions,
  9→  ProjectInfo,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import { truncateByLines, formatMultiline } from '../../utils/text.ts';
 13→import { formatToolUse } from '../../utils/format-tool.ts';
 14→import { CodexSessionCache, readMainSessionMeta } from './session-cache.ts';
 15→import {
 16→  buildCodexSubagentFiles,
 17→  extractCodexSubagentIds,
 18→} from '../../codex/watch-builder.ts';
 19→
 20→/**
 21→ * Codex Session Finder
 22→ * 目錄結構: ~/.codex/sessions/YYYY/MM/DD/rollout-*.jsonl
 23→ */
 24→class CodexSessionFinder implements SessionFinder {
 25→  private _baseDir: string;
 26→  private _cache: CodexSessionCache;
 27→
 28→  constructor() {
 29→    this._baseDir = join(homedir(), '.codex', 'sessions');
 30→    this._cache = new CodexSessionCache(this._baseDir);
 31→  }
 32→
 33→  getBaseDir(): string {
 34→    return this._baseDir;
 35→  }
 36→
 37→  /**
 38→   * 設定 baseDir（用於測試）
 39→   * 同時會重置 cache 使用新的目錄
 40→   */
 41→  setBaseDir(dir: string): void {
 42→    this._baseDir = dir;
 43→    this._cache = new CodexSessionCache(dir);
 44→  }
 45→
 46→  /**
 47→   * 取得 cache 實例（用於 findLatestInProject）
 48→   */
 49→  private get cache(): CodexSessionCache {
 50→    return this._cache;
 51→  }
 52→
 53→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 54→    const glob = new Glob('**/*.jsonl');
 55→    const files: { path: string; mtime: Date }[] = [];
 56→
 57→    for await (const file of glob.scan({
 58→      cwd: this._baseDir,
 59→      absolute: true,
 60→    })) {
 61→      // 只匹配 rollout-*.jsonl
 62→      const filename = file.split('/').pop() || '';
 63→      if (!filename.startsWith('rollout-')) continue;
 64→
 65→      // 如果有 project filter，做模糊比對（對 Codex 來說是日期過濾）
 66→      if (options.project) {
 67→        const pattern = options.project.toLowerCase();
 68→        if (!file.toLowerCase().includes(pattern)) continue;
 69→      }
 70→
 71→      // 排除 subagent session
 72→      const meta = await readMainSessionMeta(file);
 73→      if (!meta) continue;
 74→
 75→      try {
 76→        const stats = await stat(file);
 77→        files.push({ path: file, mtime: stats.mtime });
 78→      } catch {
 79→        // 忽略無法讀取的檔案
 80→      }
 81→    }
 82→
 83→    if (files.length === 0) return null;
 84→
 85→    // 按修改時間排序，取最新的
 86→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 87→
 88→    const latest = files[0];
 89→    if (!latest) return null;
 90→
 91→    return {
 92→      path: latest.path,
 93→      mtime: latest.mtime,
 94→      agentType: 'codex',
 95→    };
 96→  }
 97→
 98→  /**
 99→   * 依 session ID 查找 session 檔案
100→   * 檔名格式：rollout-{timestamp}-{sessionId}.jsonl
101→   * 支援匹配：session ID（ULID）、時間戳
102→   */
103→  async findBySessionId(
104→    sessionId: string,
105→    options: { project?: string }
106→  ): Promise<SessionFile | null> {
107→    const glob = new Glob('**/*.jsonl');
108→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
109→
110→    // UUID 格式的正規表達式（用於提取 session ID）
111→    const ulidPattern =
112→      /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.jsonl$/i;
113→
114→    for await (const file of glob.scan({
115→      cwd: this._baseDir,
116→      absolute: true,
117→    })) {
118→      const filename = file.split('/').pop() || '';
119→      if (!filename.startsWith('rollout-')) continue;
120→
121→      // project filter
122→      if (options.project) {
123→        const pattern = options.project.toLowerCase();
124→        if (!file.toLowerCase().includes(pattern)) continue;
125→      }
126→
127→      // 從檔名提取 session ID（ULID 部分）
128→      const ulidMatch = filename.match(ulidPattern);
129→      const extractedSessionId = ulidMatch?.[1] || '';
130→
131→      // 提取時間戳部分（rollout- 和 session ID 之間的部分）
132→      // rollout-2025-11-03T20-42-15-019a49bd-...
133→      const withoutPrefix = filename.replace(/^rollout-/, '');
134→      const timestampPart = extractedSessionId
135→        ? withoutPrefix.replace(`-${extractedSessionId}.jsonl`, '')
136→        : '';
137→
138→      // 計算匹配優先級
139→      let priority = 0;
140→      const searchTerm = sessionId.toLowerCase();
141→
142→      // 1. 對 session ID 進行匹配
143→      if (extractedSessionId) {
144→        const normalizedId = extractedSessionId.toLowerCase();
145→        if (normalizedId === searchTerm) {
146→          priority = 6; // 精確匹配 session ID
147→        } else if (normalizedId.startsWith(searchTerm)) {
148→          priority = 5; // 前綴匹配 session ID
149→        } else if (normalizedId.includes(searchTerm)) {
150→          priority = 4; // 包含匹配 session ID
151→        }
152→      }
153→
154→      // 2. 對時間戳進行匹配（如果 session ID 沒有匹配到）
155→      if (priority === 0 && timestampPart) {
156→        const normalizedTimestamp = timestampPart.toLowerCase();
157→        if (normalizedTimestamp === searchTerm) {
158→          priority = 3; // 精確匹配時間戳
159→        } else if (normalizedTimestamp.startsWith(searchTerm)) {
160→          priority = 2; // 前綴匹配時間戳
161→        } else if (normalizedTimestamp.includes(searchTerm)) {
162→          priority = 1; // 包含匹配時間戳
163→        }
164→      }
165→
166→      if (priority === 0) continue;
167→
168→      try {
169→        const stats = await stat(file);
170→        candidates.push({ path: file, mtime: stats.mtime, priority });
171→      } catch {
172→        // 忽略無法讀取的檔案
173→      }
174→    }
175→
176→    if (candidates.length === 0) return null;
177→
178→    // 排序：優先級降序 > mtime 降序
179→    candidates.sort((a, b) => {
180→      if (b.priority !== a.priority) return b.priority - a.priority;
181→      return b.mtime.getTime() - a.mtime.getTime();
182→    });
183→
184→    const best = candidates[0];
185→    if (!best) return null;
186→
187→    return {
188→      path: best.path,
189→      mtime: best.mtime,
190→      agentType: 'codex',
191→    };
192→  }
193→
194→  /**
195→   * 從 session 檔案取得專案資訊（用於 auto-switch）
196→   * 解析 session_meta 取得 cwd
197→   */
198→  async getProjectInfo(sessionPath: string): Promise<ProjectInfo | null> {
199→    const meta = await readMainSessionMeta(sessionPath);
200→    if (!meta) return null;
201→    return {
202→      projectDir: meta.cwd,
203→      displayName: meta.cwd,
204→    };
205→  }
206→
207→  /**
208→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
209→   * @param cwd - 專案目錄路徑
210→   */
211→  async findLatestInProject(cwd: string): Promise<SessionFile | null> {
212→    return this.cache.getLatestByCwd(cwd);
213→  }
214→
215→  /**
216→   * 找到 subagent 檔案
217→   * - 有 subagentId：用 UUID glob 在所有日期目錄查找
218→   * - 無 subagentId：從最新 session 掃描 subagent IDs，回傳最新的 subagent 檔案
219→   *
220→   * 已知限制：無 subagentId 時，findLatest() 不保證回傳主 session（可能回傳 subagent 檔案）。
221→   * 若 extractCodexSubagentIds 回傳空陣列，會回傳 null。
222→   */
223→  async findSubagent(options: {
224→    project?: string;
225→    subagentId?: string;
226→  }): Promise<SessionFile | null> {
227→    if (options.subagentId) {
228→      // 有 subagentId：用 UUID glob 精確查找
229→      return this._findSubagentById(options.subagentId, options.project);
230→    } else {
231→      // 無 subagentId：從最新 session 掃描 subagent IDs
232→      return this._findLatestSubagent(options.project);
233→    }
234→  }
235→
236→  /**
237→   * 依 subagentId（UUID 前綴或完整 UUID）在所有日期目錄查找 subagent 檔案
238→   */
239→  private async _findSubagentById(
240→    subagentId: string,
241→    project?: string
242→  ): Promise<SessionFile | null> {
243→    const glob = new Glob('**/*.jsonl');
244→    const candidates: { path: string; mtime: Date }[] = [];
245→
246→    for await (const file of glob.scan({
247→      cwd: this._baseDir,
248→      absolute: true,
249→    })) {
250→      const filename = file.split('/').pop() || '';
251→      if (!filename.startsWith('rollout-')) continue;
252→
253→      // project filter
254→      if (project) {
255→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
256→      }
257→
258→      // 包含 subagentId（大小寫不敏感）
259→      if (!filename.toLowerCase().includes(subagentId.toLowerCase())) continue;
260→
261→      try {
262→        const stats = await stat(file);
263→        candidates.push({ path: file, mtime: stats.mtime });
264→      } catch {
265→        // 忽略無法讀取的檔案
266→      }
267→    }
268→
269→    if (candidates.length === 0) return null;
270→
271→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
272→    const best = candidates[0];
273→    if (!best) return null;
274→
275→    return { path: best.path, mtime: best.mtime, agentType: 'codex' };
276→  }
277→
278→  /**
279→   * 掃描所有 session，從最新的開始找第一個含 subagent IDs 的，回傳最新的 subagent 檔案
280→   *
281→   * 注意：findLatest() 不區分主 session 和 subagent session（依 mtime 排序）。
282→   * 此方法改為迭代所有候選 session，跳過不含 spawn_agent 事件的（通常是 subagent 本身）。
283→   */
284→  private async _findLatestSubagent(
285→    project?: string
286→  ): Promise<SessionFile | null> {
287→    const glob = new Glob('**/*.jsonl');
288→    const candidates: { path: string; mtime: Date }[] = [];
289→
290→    for await (const file of glob.scan({
291→      cwd: this._baseDir,
292→      absolute: true,
293→    })) {
294→      const filename = file.split('/').pop() || '';
295→      if (!filename.startsWith('rollout-')) continue;
296→
297→      if (project) {
298→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
299→      }
300→
301→      try {
302→        const stats = await stat(file);
303→        candidates.push({ path: file, mtime: stats.mtime });
304→      } catch {
305→        // 忽略無法讀取的檔案
306→      }
307→    }
308→
309→    if (candidates.length === 0) return null;
310→
311→    // 由新到舊排序，優先從最新的 session 找 subagent
312→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
313→
314→    for (const candidate of candidates) {
315→      const agentIds = await extractCodexSubagentIds(candidate.path);
316→      if (agentIds.length === 0) continue;
317→
318→      const dateDir = dirname(candidate.path);
319→      const subFiles = await buildCodexSubagentFiles(dateDir, agentIds);
320→      if (subFiles.length === 0) continue;
321→
322→      subFiles.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
323→      return subFiles[0] ?? null;
324→    }
325→
326→    return null;
327→  }
328→}
